const id = (name: string, label: string): HospitalField => ({ name, label, required: true, reference: hospitalReferences[name], placeholder: hospitalReferences[name] ? "Rechercher par nom, code ou référence..." : "UUID" });
const ref = (name: string, label: string): HospitalField => ({ name, label, reference: hospitalReferences[name], placeholder: hospitalReferences[name] ? "Rechercher par nom, code ou référence..." : "UUID" });
const text = (name: string, label: string, required = false): HospitalField => ({ name, label, required });
const auto = (name: string, label: string): HospitalField => ({ name, label, autoGenerated: true, placeholder: "Généré automatiquement" });
const area = (name: string, label: string, required = false): HospitalField => ({ name, label, type: "textarea", required });
const select = (name: string, label: string, options: string[], required = false, allowCustom = false): HospitalField => ({ name, label, type: "select", required, allowCustom, options: options.map((value) => ({ value, label: value })) });
const multi = (name: string, label: string, options: string[], required = false): HospitalField => ({ name, label, type: "multiselect", required, options: options.map((value) => ({ value, label: value })) });
const num = (name: string, label: string, required = false): HospitalField => ({ name, label, type: "number", required });
const date = (name: string, label: string, required = false): HospitalField => ({ name, label, type: "date", required });
const dt = (name: string, label: string, required = false): HospitalField => ({ name, label, type: "datetime", required });
const json = (name = "payload", label = "Données JSON", placeholder = '{"key":"value"}'): HospitalField => ({ name, label, type: "json", placeholder });
const file = (name = "file", label = "Fichier", required = false): HospitalField => ({ name, label, type: "file", required, placeholder: "PDF, image, DICOM ou document" });
const image = (name = "imageUrl", label = "Image", required = false): HospitalField => ({ name, label, type: "image", required, placeholder: "Photo prise par caméra ou importée" });
const logo = (name = "logoUrl", label = "Logo hôpital"): HospitalField => ({ name, label, type: "file", placeholder: "Image PNG, JPG ou SVG" });
const color = (name: string, label: string, placeholder = "#1d4ed8"): HospitalField => ({ name, label, type: "color", placeholder });
const modulePermissions = (name = "modulePermissions", label = "Permissions modules"): HospitalField => ({ name, label, type: "module-permissions" });
const priceListItems = (name = "items", label = "Lignes tarifaires"): HospitalField => ({ name, label, type: "price-list-items", required: true });
const purchaseOrderItems = (name = "items", label = "Articles"): HospitalField => ({ name, label, type: "purchase-order-items", required: true });
const dispensationItems = (name = "items", label = "Médicaments délivrés"): HospitalField => ({ name, label, type: "dispensation-items", required: true });
const prescriptionItems = (name = "items", label = "Médicaments prescrits"): HospitalField => ({ name, label, type: "prescription-items", required: true });
