export function hospitalMetricLabel(key: string) {
  return HOSPITAL_LABELS[key] ?? humanizeHospitalKey(key);
}

function humanizeHospitalKey(key: string) {
  return key
    .replace(/_/g, " ")
    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")
    .replace(/\b(id|icu|sms|hr|pdf|json|sku|qr)\b/gi, (match) => match.toUpperCase())
    .replace(/^./, (char) => char.toUpperCase());
}

const cols = (...keys: string[]) => keys.map((key) => ({ key, label: hospitalMetricLabel(key) }));
const resource = (key: string, title: string, endpoint: string, fields: HospitalField[], columns = cols("id", "status", "createdAt"), extra: Partial<HospitalResource> = {}): HospitalResource => ({ key, title, description: extra.description ?? `Connecté à ${endpoint}`, endpoint, fields, columns, canCreate: true, canUpdate: true, canDelete: false, ...extra });
const dashboard = (key: string, title: string, endpoint: string, columns: string[], description: string): HospitalResource => resource(key, title, endpoint, [], cols(...columns), { canCreate: false, canUpdate: false, description });

